-- =====================================================================
-- Grocery Store Sales Database (MySQL 8.0+)
-- Period covered: 2024-10-15 to 2026-05-31
-- =====================================================================

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

CREATE DATABASE IF NOT EXISTS grocery_store
  CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE grocery_store;

-- ---------------------------------------------------------------------
-- Table: store
-- ---------------------------------------------------------------------
DROP TABLE IF EXISTS transaction_items;
DROP TABLE IF EXISTS transactions;
DROP TABLE IF EXISTS customers;
DROP TABLE IF EXISTS products;
DROP TABLE IF EXISTS store;

CREATE TABLE store (
    store_id    INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    store_name  VARCHAR(150)  NOT NULL,
    area        VARCHAR(100),
    city        VARCHAR(100),
    state       VARCHAR(100)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ---------------------------------------------------------------------
-- Table: customers
-- phone_number is UNIQUE -> same phone always resolves to same customer_id
-- ---------------------------------------------------------------------
CREATE TABLE customers (
    customer_id        INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    customer_name       VARCHAR(150)  NOT NULL,
    phone_number         VARCHAR(15)   NOT NULL,
    area                 VARCHAR(100),
    registration_date    DATE          NOT NULL,
    customer_segment     ENUM('Regular','Occasional','New') DEFAULT 'New',
    UNIQUE KEY uq_customers_phone (phone_number),
    INDEX idx_customers_segment (customer_segment)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ---------------------------------------------------------------------
-- Table: products
-- ---------------------------------------------------------------------
CREATE TABLE products (
    product_id    INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    product_name   VARCHAR(150)   NOT NULL,
    category        VARCHAR(100)   NOT NULL,
    unit             VARCHAR(20)    NOT NULL,
    unit_price       DECIMAL(10,2)  NOT NULL,
    INDEX idx_products_category (category)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ---------------------------------------------------------------------
-- Table: transactions  (one row per bill / checkout)
-- ---------------------------------------------------------------------
CREATE TABLE transactions (
    transaction_id        INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    customer_id            INT UNSIGNED NOT NULL,
    store_id                INT UNSIGNED NOT NULL,
    transaction_datetime    DATETIME     NOT NULL,
    payment_mode             ENUM('Cash','UPI','Card') NOT NULL,
    total_amount              DECIMAL(10,2) NOT NULL,
    total_items                SMALLINT UNSIGNED NOT NULL,
    CONSTRAINT fk_txn_customer FOREIGN KEY (customer_id) REFERENCES customers(customer_id)
        ON UPDATE CASCADE ON DELETE RESTRICT,
    CONSTRAINT fk_txn_store FOREIGN KEY (store_id) REFERENCES store(store_id)
        ON UPDATE CASCADE ON DELETE RESTRICT,
    INDEX idx_txn_customer (customer_id),
    INDEX idx_txn_datetime (transaction_datetime)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ---------------------------------------------------------------------
-- Table: transaction_items (line items within a bill)
-- ---------------------------------------------------------------------
CREATE TABLE transaction_items (
    transaction_item_id   INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    transaction_id          INT UNSIGNED NOT NULL,
    product_id                INT UNSIGNED NOT NULL,
    quantity                    SMALLINT UNSIGNED NOT NULL,
    unit_price                    DECIMAL(10,2) NOT NULL,
    subtotal                        DECIMAL(10,2) NOT NULL,
    CONSTRAINT fk_item_txn FOREIGN KEY (transaction_id) REFERENCES transactions(transaction_id)
        ON UPDATE CASCADE ON DELETE CASCADE,
    CONSTRAINT fk_item_product FOREIGN KEY (product_id) REFERENCES products(product_id)
        ON UPDATE CASCADE ON DELETE RESTRICT,
    INDEX idx_items_txn (transaction_id),
    INDEX idx_items_product (product_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

